+                log.debug("%s: received secret key from keyserver %s", local_addr, msg.getSrc());
+                setKeys(tmp, key_version);
+            }
+        }
+        catch(Exception e) {
+            log.warn("%s: unable to process received public key", local_addr, e);
+        }
+    }
